// =============================================================================
// applyCornerMap — A1 deterministic corner_map derive from result rows
// =============================================================================

/**
 * A1: DERIVE `corner_map` from the result rows when the answer is about a
 * SINGLE named corner — a single-corner metric card. The LLM does not
 * reliably emit corner_map, so when the rows carry exactly one distinct
 * `corner_number` (or, as a fallback, one distinct `corner_label`) together
 * with a `circuit_short_name`, we set corner_map here so <CornerMiniMap>
 * (resolved client-side against the real track outline) can render.
 *
 * Guards (mirrors applyScalarHero's conservatism):
 *   - never overwrite an existing corner_map (LLM synthesis path wins)
 *   - require a resolvable circuit (circuit_short_name column)
 *   - require EXACTLY ONE distinct corner — multi-corner grouped-bar
 *     results (many corner_number/corner_label values) are NOT single-corner
 *   - require the corner column to be present — non-corner results are skipped
 */
export function applyCornerMap(insight: DraftInsight): DraftInsight {
  if (insight.corner_map) return insight;
  const rows = insight.rows;
  if (!rows || rows.length === 0) return insight;
  const cols = Object.keys(rows[0]);

  // Circuit is mandatory — the mini-map resolves the outline by circuit name.
  if (!cols.includes("circuit_short_name")) return insight;
  const circuits = new Set(
    rows
      .map((r) => (typeof r.circuit_short_name === "string" ? r.circuit_short_name.trim() : ""))
      .filter((c) => c.length > 0)
  );
  if (circuits.size !== 1) return insight;
  const circuit = [...circuits][0];

  // Prefer corner_number (numeric); fall back to corner_label. Require the
  // result to describe EXACTLY ONE corner — otherwise it is a multi-corner
  // (grouped-bar) shape, not a single-corner card.
  if (cols.includes("corner_number")) {
    const numbers = new Set(
      rows
        .map((r) => r.corner_number)
        .filter((v): v is number => typeof v === "number" && Number.isFinite(v))
    );
    if (numbers.size !== 1) return insight;
    const cornerNumber = [...numbers][0];
    const labelForNum = rows.find((r) => r.corner_number === cornerNumber)?.corner_label;
    return {
      ...insight,
      corner_map: {
        circuit,
        corner_number: cornerNumber,
        corner_label:
          typeof labelForNum === "string" && labelForNum.trim().length > 0
            ? labelForNum.trim()
            : undefined
      }
    };
  }

  if (cols.includes("corner_label")) {
    const labels = new Set(
      rows
        .map((r) => (typeof r.corner_label === "string" ? r.corner_label.trim() : ""))
        .filter((c) => c.length > 0)
    );
    if (labels.size !== 1) return insight;
    return { ...insight, corner_map: { circuit, corner_label: [...labels][0] } };
  }

  // No corner column present — not a corner result.
  return insight;
}

