  build(rows) {
    const cols = Object.keys(rows[0]);
    const labelCol =
      findCol(cols, /session_label|label|name/) ?? cols.find((c) => /session/.test(c)) ?? cols[0];
    const coverageVals = new Set(["full", "partial", "missing"]);
    const coverageCols = cols.filter((c) => {
      const v = rows[0][c];
      return typeof v === "string" && coverageVals.has(v.toLowerCase());
    });
    const legacyRows = rows.map((r) => {
      const cells: Record<string, string | number | undefined> = {};
      for (const c of coverageCols) cells[c] = String(r[c] ?? "missing");
      return {
        session_key: isNumericLike(r.session_key) ? toNumber(r.session_key) : undefined,
        label: String(r[labelCol] ?? ""),
        ...cells
      };
    });

    // Venue-grid mode: when the rows carry a circuit key (the M18 telemetry-
    // vs-weather template), roll every session up to a per-VENUE status so
    // the renderer can draw a 24-circuit coverage grid. A session is a "gap"
    // if ANY coverage column is missing/partial. Venue is green with zero
    // gaps, red when EVERY session is a gap, amber otherwise.
    const hasCircuit = cols.includes("circuit_short_name");
    if (hasCircuit) {
      const acc = new Map<
        string,
        { circuit: string; location: string; round?: number; total: number; gaps: number }
      >();
      for (const r of rows) {
        const circuit = String(r.circuit_short_name ?? "").trim();
        if (!circuit) continue;
        const sessionHasGap = coverageCols.some((c) => {
          const v = String(r[c] ?? "missing").toLowerCase();
          return v === "missing" || v === "partial";
        });
        const entry =
          acc.get(circuit) ??
          {
            circuit,
            location: String(r.location ?? circuit),
            round: isNumericLike(r.round) ? toNumber(r.round) : undefined,
            total: 0,
            gaps: 0
          };
        entry.total += 1;
        if (sessionHasGap) entry.gaps += 1;
        if (entry.round === undefined && isNumericLike(r.round)) entry.round = toNumber(r.round);
        acc.set(circuit, entry);
      }
      const venues = [...acc.values()]
        .map((v) => ({
          circuit: v.circuit,
          location: v.location,
          round: v.round,
          total: v.total,
          gaps: v.gaps,
          status: (v.gaps === 0 ? "green" : v.gaps >= v.total ? "red" : "amber") as
            | "green"
            | "amber"
            | "red"
        }))
        .sort((a, b) => (a.round ?? 999) - (b.round ?? 999) || a.location.localeCompare(b.location));
      if (venues.length > 0) {
        return {
          type: "status_grid",
          venue_grid: true,
          venues,
          rows: legacyRows,
          legend: { full: "#22C55E", partial: "#F59E0B", missing: "#EF4444" }
        };
      }
    }

    return {
      type: "status_grid",
      rows: legacyRows,
      legend: { full: "#22C55E", partial: "#F59E0B", missing: "#EF4444" }
    };
  }

Full new file contents. Branches on chart.venue_grid: venue mode renders the 24-circuit CSS grid (each tile a VenueTile that lazily fetches its own outline via useTrackOutline and tints a single full-lap TrackMap segment); the legacy path renders the original session×datatype table verbatim. Keeps an all-clear empty state.

"use client"

import { useMemo } from "react"
import type { ChartSpec, VenueCoverage } from "@/lib/chart-types"
import { cn } from "@/lib/utils"
import { TrackMap, useTrackOutline } from "./track-map"

interface StatusGridChartProps {
  chart: ChartSpec
}

// Status tints follow the two-layer color rule: coverage status is a THEME
// semantic (not a team/compound domain color), so use hsl(var(--token)).
const STATUS_TINT: Record<VenueCoverage["status"], string> = {
  green: "hsl(var(--semantic-positive))",
  amber: "hsl(var(--accent-amber))",
  red: "hsl(var(--semantic-negative))"
}

const STATUS_LABEL: Record<VenueCoverage["status"], string> = {
  green: "Complete",
  amber: "Partial",
  red: "Gap"
}

const STATUS_COLORS: Record<string, { bg: string; text: string }> = {
  full: { bg: "bg-emerald-500/20", text: "text-emerald-400" },
  partial: { bg: "bg-amber-500/20", text: "text-amber-400" },
  missing: { bg: "bg-red-500/20", text: "text-red-400" }
}

/** One venue tile: lazily fetches its own outline (useTrackOutline caches
 *  per circuit, and each tile mounts independently so the 24
 *  /api/track-outline requests fan out one-per-circuit). Renders a mini
 *  outline tinted by the venue's coverage status, with an Rn round label. */
function VenueTile({ venue }: { venue: VenueCoverage }) {
  const outline = useTrackOutline(venue.circuit)
  const tint = STATUS_TINT[venue.status]
  const roundLabel = venue.round !== undefined ? `R${venue.round}` : "—"

  return (
    <div
      className="flex flex-col items-center gap-1 rounded-lg border border-border/40 bg-surface-raised p-2"
      title={`${venue.location} — ${STATUS_LABEL[venue.status]} (${venue.gaps}/${venue.total} sessions with a weather gap)`}
    >
      <div className="flex w-full items-center justify-between px-0.5">
        <span className="font-mono text-[9px] uppercase tracking-[0.12em] text-section-label">
          {roundLabel}
        </span>
        <span className="size-2 rounded-full" style={{ backgroundColor: tint }} />
      </div>
      <div className="flex h-16 w-full items-center justify-center">
        {outline === undefined ? (
          <div className="size-full animate-pulse rounded bg-foreground/5" />
        ) : outline === null ? (
